import numpy as np


def _sample(probs, rng):
    u = rng.random()
    c = 0.0
    for i, pi in enumerate(probs):
        c += float(pi)
        if u < c:
            return i
    return len(probs) - 1


def _residual(q, p):
    raw = [max(0.0, float(qi) - float(pi)) for qi, pi in zip(q, p)]
    s = sum(raw)
    if s == 0.0:
        return [float(qi) for qi in q]
    return [r / s for r in raw]


def spec_step(q, p, N, rng):
    q = list(q)
    p = list(p)
    n_accepted = 0
    for _ in range(N):
        d = _sample(p, rng)
        q_prob = float(q[d])
        p_prob = float(p[d])
        ratio = q_prob / p_prob if p_prob > 0 else float("inf")
        u = rng.random()
        if u < min(1.0, ratio):
            n_accepted += 1
        else:
            return _sample(_residual(q, p), rng), n_accepted
    return _sample(q, rng), N
